sql:
SELECT COUNT(*)
FROM model_architectures
WHERE architecture_details LIKE '%dense%';

SELECT nn.model_name, mp.prediction_timestamp
FROM neural_network_models AS nn
JOIN model_predictions AS mp ON nn.model_id = mp.model_id;

SELECT mp.prediction_id, mp.model_id, nnm.model_name
FROM model_predictions mp
INNER JOIN neural_network_models nnm ON mp.model_id = nnm.model_id;

SELECT * 
FROM model_architectures 
WHERE model_id = 1;

SELECT model_name
FROM neural_network_models
WHERE model_id = 1;

external_knowledge:
- "top performing models" refers to models with the highest metric values;
- The terms "details" and "best performance" imply the retrieval of the model name and the highest metric values;
- The limitation to "top" suggests an ordering and a limit on the number of results to the best 4.

sql:
SELECT model_id
FROM training_datasets
WHERE dataset_name = 'Dataset A';

SELECT environment, COUNT(*) as num_models
FROM model_deployments
GROUP BY environment;

SELECT ms.model_id, u.user_name
FROM model_shares ms
JOIN users u ON ms.shared_with_user_id = u.user_id;

SELECT model_id, model_name
FROM neural_network_models
WHERE training_duration > (SELECT AVG(training_duration) FROM neural_network_models);
